// PAHA 2011-08-30, FWI Foundation - 46890 Text block management -->
// Some methods are transferred from AX2009, but structure is new
// KLSI 2012-03-21, FWI Foundation - 46890 Text block management -->
// Split code to several classes
class FWFTextBlockValueSubstitutor
{
    public const str    TextPlaceHolderStart = '{';
    public const str    TextPlaceHolderEnd = '}';
    public const str    PlaceholderPartSeparator = '.';
    public const str    Comma = ',';
    public const str    JournalTable = 'Jour';
    public const str    JournalTrans = 'Trans';
    public const str    SourceTable = 'Source';
    public const str    InterpError = 'ERROR';

    Common                      sourceRecord;
    Common                      targetRecord;
    str                         textBlockText;
    str                         resultText;

    SalesTable                  salesTable;
    SalesLine                   salesLine;
    PurchTable                  purchTable;
    PurchLine                   purchLine;
    SalesQuotationTable         salesQuotationTable;
    SalesQuotationLine          salesQuotationLine;
    CustTable                   custTable;
    smmBusRelTable              smmBusRelTable;
    ProdTable                   prodTable;
    AgreementLine               agreementLine;
    SalesAgreementHeader        salesAgreementHeader;
    PurchAgreementHeader        purchAgreementHeader;
    BOM                         bom;
    CustInvoiceTable			custInvoiceTable;
    CustIntentLetter_IT			custIntentLetter_IT;
    EcoResProduct               ecoResProduct;
    EcoResDistinctProductVariant   ecoResDistinctProductVariant;
    InventDistinctProductExpanded  inventDistinctProductExpanded;
    CustGroup                   custGroup;
    VendGroup                   vendGroup;

    VendTable					vendTable;
    InventTable					inventTable;

    Common                      targetJour;
    Common                      targetTrans;

}

